import React from 'react';

const ResultPage = ({ result, teamInfo }) => {
  const { score, totalQuestions, timeTaken } = result;
  const percentage = Math.round((score / totalQuestions) * 100);

  const formatTime = (microseconds) => {
    const seconds = Math.floor(microseconds / 1_000_000);
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes}m ${remainingSeconds}s`;
  };

  return (
    <div style={{
      maxWidth: '450px',
      margin: '60px auto',
      padding: '30px',
      backgroundColor: 'white',
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Arial, sans-serif',
      textAlign: 'center'
    }}>
      <h1 style={{ fontSize: '28px', marginBottom: '10px', color: '#111' }}>Quiz Complete!</h1>
      <p style={{ color: '#666', marginBottom: '30px' }}>{teamInfo.teamName}</p>

      <div style={{ marginBottom: '30px' }}>
        <div style={{ fontSize: '48px', fontWeight: '600', color: '#2563eb', marginBottom: '10px' }}>
          {score}/{totalQuestions}
        </div>
        <div style={{ fontSize: '18px', color: '#374151' }}>
          {percentage}% • {formatTime(timeTaken)}
        </div>
      </div>

      <button
        onClick={() => window.location.reload()}
        style={{
          padding: '12px 32px',
          backgroundColor: '#2563eb',
          color: 'white',
          border: 'none',
          borderRadius: '4px',
          fontSize: '16px',
          cursor: 'pointer'
        }}
      >
        Take Another Quiz
      </button>
    </div>
  );
};

export default ResultPage;
